def get_song(title: str) -> dict:
    """Return knowledge dict for a song title (case-sensitive)."""
    if title not in SONG_KNOWLEDGE:
        # Try case-insensitive fallback
        title_lower = title.lower()
        for k in SONG_KNOWLEDGE:
            if k.lower() == title_lower:
                return SONG_KNOWLEDGE[k]
        return {}
    return SONG_KNOWLEDGE[title]


def get_genre(genre: str) -> dict:
    """Return dict of {title: knowledge} for all songs in a genre."""
    genre_upper = genre.upper()
    titles = GENRE_INDEX.get(genre_upper, [])
    return {t: SONG_KNOWLEDGE[t] for t in titles if t in SONG_KNOWLEDGE}


def search_songs(query: str) -> list:
    """Case-insensitive search across all song titles. Returns list of matching titles."""
    q = query.lower()
    return [t for t in SONG_KNOWLEDGE if q in t.lower()]


def list_genres() -> list:
    """Return list of all available genres."""
    return list(GENRE_INDEX.keys())


def song_count() -> int:
    """Return total number of songs in the database."""
    return len(SONG_KNOWLEDGE)


if __name__ == "__main__":
    print(f"Song Knowledge Database loaded: {song_count()} songs across {len(list_genres())} genres")
    print("Genres:", ", ".join(list_genres()))
    print()
    # Sample lookup
    sample = get_song("Bohemian Rhapsody")
    if sample:
        print("Sample entry — Bohemian Rhapsody:")
        for k, v in sample.items():
            print(f"  {k}: {v}")
